WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/18.0/connection.js")}

var StageValue= "{!Opportunity.StageName}";
var profile = "{!$Profile.Name}";

if ((profile=='Informatics Operations' ||profile=='System Administrator') && (StageValue == 'Stage 6 - Implement (Closed)' || StageValue == 'Closed Won'))
{
var url = "https://perkinelmer.my.salesforce.com/apex/RejectPage?oppId={!Opportunity.Id}&oopOwner={!Opportunity.OwnerEmail}&OwnerName={!Opportunity.OwnerFullName}";
window.open(url,'Reject','centerscreen,dependent=NO,dialog=YES,modal=YES,status=0,toolbar=0,width=500,height=210,scrollbars=1,resizable=1,left=180,top=260,screenX=180,screenY=260');
}
else
{
alert("Invalid Operation");
}
